      {"type":"type-answer","question":"Переведите: Врач","acceptedAnswers":["医生","yīshēng","yisheng"]},
      {"type":"flashcards","cards":[{"front":"老师 (lǎoshī)","back":"Учитель"},{"front":"医生 (yīshēng)","back":"Врач"},{"front":"学生 (xuéshēng)","back":"Студент"},{"front":"工程师 (gōngchéngshī)","back":"Инженер"},{"front":"工作 (gōngzuò)","back":"Работа / работать"},{"front":"经理 (jīnglǐ)","back":"Менеджер"}]},
